class Solution {
public:
    void moveZeroes(vector<int>& nums) {
        int zeros = 0;
        if(nums.size() == 1){
            return;
        }
        for(int i = 0; i < nums.size(); i++){
            if(nums[i] == 0){
                zeros++;
            }
        }
        remove(nums.begin(),nums.end(),0);
        for(int x = 0; x <= zeros; x++){
            nums[nums.size() - x] = 0;
    }}
};

